function a(l){return String(l??"").replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#39;")}function c(l){const e=Number(l);if(!Number.isFinite(e)||e<=0)return"0 B";if(e<1024)return`${e} B`;const n=["KB","MB","GB"];let t=e/1024,r=0;for(;t>=1024&&r<n.length-1;)t/=1024,r+=1;const i=t>=10?0:1;return`${t.toFixed(i)} ${n[r]}`}export{a as e,c as f};
